// ═══════════════════════════════════════════════════
// NODE: Extract & Sanitize Message
// Purpose: Parse Evolution API payload, strip PII from logs
// ═══════════════════════════════════════════════════

const body = $input.first().json.body || $input.first().json;

// --- Evolution API payload structure ---
const event = body.event || '';
const instance = body.instance || '';

// Support both Evolution API v1 and v2 payload shapes
let senderId = '';
let messageText = '';
let messageId = '';
let pushName = '';

if (body.data && body.data.key) {
  // Evolution API v2 format
  senderId = body.data.key.remoteJid || '';
  messageId = body.data.key.id || '';
  pushName = body.data.pushName || '';
  messageText = body.data.message?.conversation 
    || body.data.message?.extendedTextMessage?.text 
    || body.data.message?.imageMessage?.caption
    || '';
} else if (body.messages && body.messages[0]) {
  // Evolution API v1 format
  const msg = body.messages[0];
  senderId = msg.key?.remoteJid || '';
  messageId = msg.key?.id || '';
  pushName = msg.pushName || '';
  messageText = msg.message?.conversation 
    || msg.message?.extendedTextMessage?.text
    || '';
}

// Normalize sender ID (strip @s.whatsapp.net suffix for comparison)
const senderPhone = senderId.replace('@s.whatsapp.net', '').replace('@g.us', '');

// --- PII Sanitizer for safe logging (before any external call) ---
const sanitizedText = messageText
  .replace(/\b[\w._%+-]+@[\w.-]+\.[A-Z]{2,}\b/gi, '[EMAIL_REDACTED]')
  .replace(/\b(\+?\d[\d\s\-().]{7,}\d)\b/g, '[PHONE_REDACTED]')
  .replace(/\b\d{4}[\s-]?\d{4}[\s-]?\d{4}[\s-]?\d{4}\b/g, '[CARD_REDACTED]');

// Ignore messages from self (bot's own number) or group messages (for now)
const isFromMe = body.data?.key?.fromMe || false;
const isGroup = senderId.includes('@g.us');

if (isFromMe || isGroup || !messageText.trim()) {
  // Return a stop signal
  return [{ json: { __stop: true, reason: 'self_or_group_or_empty' } }];
}

return [{
  json: {
    __stop: false,
    senderId,
    senderPhone,
    messageText,          // original - used for AI
    sanitizedText,        // sanitized - used for logging
    messageId,
    pushName,
    instance,
    event,
    receivedAt: new Date().toISOString()
  }
}];

// ═══════════════════════════════════════════════════
// NODE: Gatekeeper - Whitelist Check
// Purpose: Determine if sender is authorized and their type
// ═══════════════════════════════════════════════════

const incoming = $('Extract & Sanitize Message').first().json;
const sheetData = $input.first().json;

const senderPhone = incoming.senderPhone.trim();
const rows = sheetData.values || [];

// Skip header row (row 0 = headers: Phone, Name, Tag, Status)
let authorized = false;
let contactName = '';
let contactTag = 'Personal'; // default
let contactStatus = 'Active';

for (let i = 1; i < rows.length; i++) {
  const row = rows[i];
  const sheetPhone = (row[0] || '').toString().trim().replace(/[^0-9+]/g, '');
  const normalizedSender = senderPhone.replace(/[^0-9+]/g, '');

  if (sheetPhone === normalizedSender || sheetPhone === '+' + normalizedSender) {
    contactStatus = (row[3] || 'Active').trim();
    if (contactStatus.toLowerCase() === 'active') {
      authorized = true;
      contactName = (row[1] || incoming.pushName || 'Contact').trim();
      contactTag = (row[2] || 'Personal').trim(); // 'Client' or 'Personal'
    }
    break;
  }
}

return [{
  json: {
    ...incoming,
    authorized,
    contactName,
    contactTag,
    contactStatus
  }
}];

// ═══════════════════════════════════════════════════
// NODE: Build System Prompt
// Purpose: Dynamic personality based on contact tag
// ═══════════════════════════════════════════════════

const data = $input.first().json;
const tag = data.contactTag || 'Personal';
const name = data.contactName || 'there';

let systemPrompt = '';

if (tag.toLowerCase() === 'client') {
  systemPrompt = `You are a professional assistant for WebCorps, a digital agency. You are responding to ${name}, a valued client.

Guidelines:
- Maintain a formal, polished, and solution-oriented tone
- Use *bold text* for important terms and key points
- Use bullet points where listing multiple items for clarity
- Keep responses concise but complete — never leave a question unanswered
- Always end with an offer to assist further if needed
- Do NOT mention that you are an AI unless directly asked
- Response language: match the language the client uses (Urdu/English)`;
} else {
  systemPrompt = `You are a helpful personal assistant. You are chatting with ${name}.

Guidelines:
- Be casual, friendly, and brief — like texting a smart friend
- Use bullet points only when listing 3+ items
- Skip unnecessary formalities
- Match the energy of the message (short question = short answer)
- Do NOT mention that you are an AI unless directly asked
- Response language: match the language used (Urdu/English/Roman Urdu)`;
}

// Choose model based on message complexity
const msgLength = (data.messageText || '').length;
const wordCount = (data.messageText || '').split(' ').length;
const isComplex = wordCount > 20 || data.messageText.includes('?') && wordCount > 10;

// Use Scout for quick/short replies, 70B for complex queries
const selectedModel = isComplex 
  ? 'llama-3.3-70b-versatile' 
  : 'meta-llama/llama-4-scout-17b-16e-instruct';

return [{
  json: {
    ...data,
    systemPrompt,
    selectedModel,
    isComplex
  }
}];

// ═══════════════════════════════════════════════════
// NODE: Assemble Messages Array
// Purpose: Build the full messages array for Groq API
// ═══════════════════════════════════════════════════

const promptData = $('Build System Prompt').first().json;
const memoryRaw = $input.first().json;

// Memory rows come back newest-first from Supabase, so reverse for chronological order
const memoryRows = Array.isArray(memoryRaw) ? memoryRaw.reverse() : [];

const messages = [];

// Add historical turns (max 10 turns = 20 messages, but we fetched 10 rows)
for (const row of memoryRows) {
  messages.push({
    role: row.role,   // 'user' or 'assistant'
    content: row.content
  });
}

// Add the current user message
messages.push({
  role: 'user',
  content: promptData.messageText
});

return [{
  json: {
    ...promptData,
    messages,
    memoryCount: memoryRows.length
  }
}];

// ═══════════════════════════════════════════════════
// NODE: Rate Limit Handler
// Purpose: Check Groq headers for rate limits, set wait flag
// ═══════════════════════════════════════════════════

const response = $input.first();
const statusCode = response.json.statusCode || 200;
const headers = response.json.headers || {};
const body = response.json.body || response.json;

// Groq rate limit headers
const remainingRequests = parseInt(headers['x-ratelimit-remaining-requests'] || '100');
const remainingTokens = parseInt(headers['x-ratelimit-remaining-tokens'] || '100000');
const resetRequestsMs = parseInt((headers['x-ratelimit-reset-requests'] || '0s').replace('s','')) * 1000;
const resetTokensMs = parseInt((headers['x-ratelimit-reset-tokens'] || '0s').replace('s','')) * 1000;

let rateLimited = false;
let waitMs = 0;
let aiReply = '';

if (statusCode === 429) {
  // Rate limited — calculate wait time
  rateLimited = true;
  waitMs = Math.max(resetRequestsMs, resetTokensMs, 60000); // min 60s wait
  aiReply = ''; // will retry after wait
} else if (statusCode === 200 || (body.choices && body.choices[0])) {
  // Success
  aiReply = body.choices?.[0]?.message?.content || body.body?.choices?.[0]?.message?.content || '';

  // Proactive throttle: if < 5 requests remaining, schedule a short pause
  if (remainingRequests < 5 || remainingTokens < 5000) {
    rateLimited = true;
    waitMs = Math.max(resetRequestsMs, resetTokensMs, 10000);
  }
} else {
  aiReply = "I'm having trouble processing that right now. Please try again in a moment.";
}

// Get context from upstream
const upstream = $('Assemble Messages Array').first().json;

return [{
  json: {
    ...upstream,
    aiReply,
    rateLimited,
    waitMs,
    statusCode,
    remainingRequests,
    remainingTokens
  }
}];

// ═══════════════════════════════════════════════════
// NODE: Merge AI Reply
// Purpose: Unify reply from first attempt or retry
// ═══════════════════════════════════════════════════

let aiReply = '';
let upstream = {};

// Check if we came from retry path or direct path
try {
  const retryData = $('Groq Retry After Throttle').first();
  if (retryData && retryData.json) {
    const body = retryData.json;
    aiReply = body.choices?.[0]?.message?.content || '';
    upstream = $('Rate Limit Handler').first().json;
  }
} catch(e) {
  // Came from direct (non-rate-limited) path
  upstream = $('Rate Limit Handler').first().json;
  aiReply = upstream.aiReply;
}

if (!aiReply) {
  aiReply = "Sorry, I couldn't get a response right now. Please try again in a moment. 🙏";
}

return [{
  json: {
    ...upstream,
    aiReply
  }
}];

