// ═══════════════════════════════════════════════════
// NODE: Prune Old Memory
// Purpose: Keep only last 10 turns per contact (20 rows)
// ═══════════════════════════════════════════════════

// This runs a Supabase RPC or delete query to trim old rows
// We'll use a simple approach: delete rows older than the 20th newest per phone

const phone = $('Merge AI Reply').first().json.senderPhone;

// We return the delete query parameters for the next HTTP node
return [{
  json: {
    phone,
    pruneQuery: `phone=eq.${phone}&id=not.in.(select id from conversation_memory where phone=eq.${phone} order by created_at desc limit 20)`
  }
}];
